// Cache entry wrapper with TTL support
class CacheEntry<V extends Serializable> implements Serializable {
    private static final long serialVersionUID = 1L;
    
    private String key;
    private V value;
    private long createdAt;
    private long ttlMillis;
    private long lastAccessedAt;
    private int accessCount;
    
    public CacheEntry(String key, V value, long ttlMillis) {
        this.key = key;
        this.value = value;
        this.createdAt = System.currentTimeMillis();
        this.ttlMillis = ttlMillis;
        this.lastAccessedAt = this.createdAt;
        this.accessCount = 0;
    }
    
    public String getKey() { return key; }
    
    public V getValue() {
        this.lastAccessedAt = System.currentTimeMillis();
        this.accessCount++;
        return value;
    }
    
    public boolean isExpired() {
        if (ttlMillis <= 0) return false; // no expiry
        return System.currentTimeMillis() > createdAt + ttlMillis;
    }
    
    public long getLastAccessedAt() { return lastAccessedAt; }
    public int getAccessCount() { return accessCount; }
    public long getCreatedAt() { return createdAt; }
}

// Statistics tracking
class CacheStatistics {
    private final AtomicLongMap hits = new AtomicLongMap();
    private final AtomicLongMap misses = new AtomicLongMap();
    private final AtomicLongMap diskReads = new AtomicLongMap();
    private final AtomicLongMap diskWrites = new AtomicLongMap();
    private final AtomicLongMap evictions = new AtomicLongMap();
    
    // Simple atomic long map replacement
    static class AtomicLongMap {
        private final ConcurrentHashMap<String, Long> map = new ConcurrentHashMap<>();
        
        public void increment(String key) {
            map.merge(key, 1L, Long::sum);
        }
        
        public long get(String key) {
            return map.getOrDefault(key, 0L);
        }
        
        public long total() {
            return map.values().stream().mapToLong(Long::longValue).sum();
        }
    }
    
    public void recordHit() { hits.increment("total"); }
    public void recordMiss() { misses.increment("total"); }
    public void recordDiskRead() { diskReads.increment("total"); }
    public void recordDiskWrite() { diskWrites.increment("total"); }
    public void recordEviction() { evictions.increment("total"); }
    
    public long getHits() { return hits.total(); }
    public long getMisses() { return misses.total(); }
    public long getDiskReads() { return diskReads.total(); }
    public long getDiskWrites() { return diskWrites.total(); }
    public long getEvictions() { return evictions.total(); }
    
    public double getHitRate() {
        long total = getHits() + getMisses();
        return total == 0 ? 0.0 : (double) getHits() / total;
    }
    
    @Override
    public String toString() {
        return String.format("CacheStats{hits=%d, misses=%d, hitRate=%.2f%%, diskReads=%d, diskWrites=%d, evictions=%d}",
                getHits(), getMisses(), getHitRate() * 100, getDiskReads(), getDiskWrites(), getEvictions());
    }
}

// Main disk-backed cache
class DiskCache<V extends Serializable> {
    
    private final Path cacheDirectory;
    private final ConcurrentHashMap<String, CacheEntry<V>> memoryCache;
    private final ReadWriteLock lock;
    private final int maxMemoryEntries;
    private final long defaultTtlMillis;
    private final CacheStatistics statistics;
    private final ScheduledExecutorService cleanupExecutor;
    
    public DiskCache(String cacheDir, int maxMemoryEntries, long defaultTtlMillis) throws IOException {
        this.cacheDirectory = Paths.get(cacheDir);
        Files.createDirectories(this.cacheDirectory);
        this.memoryCache = new ConcurrentHashMap<>();
        this.lock = new ReentrantReadWriteLock();
        this.maxMemoryEntries = maxMemoryEntries;
        this.defaultTtlMillis = defaultTtlMillis;
        this.statistics = new CacheStatistics();
        
        // Schedule periodic cleanup
        this.cleanupExecutor = Executors.newSingleThreadScheduledExecutor(r -> {
            Thread t = new Thread(r, "cache-cleanup");
            t.setDaemon(true);
            return t;
        });
        this.cleanupExecutor.scheduleAtFixedRate(this::cleanup, 60, 60, TimeUnit.SECONDS);
        
        // Load existing disk entries index
        loadIndexFromDisk();
    }
    
    public void put(String key, V value) {
        put(key, value, defaultTtlMillis);
    }
    
    public void put(String key, V value, long ttlMillis) {
        lock.writeLock().lock();
        try {
            CacheEntry<V> entry = new CacheEntry<>(key, value, ttlMillis);
            
            // Check if we need to evict from memory
            if (memoryCache.size() >= maxMemoryEntries && !memoryCache.containsKey(key)) {
                evictLeastRecentlyUsed();
            }
            
            memoryCache.put(key, entry);
            
            // Persist to disk asynchronously
            serializeToDisk(key, entry);
        } finally {
            lock.writeLock().unlock();
        }
    }
    
    @SuppressWarnings("unchecked")
    public V get(String key) {
        lock.readLock().lock();
        try {
            // Check memory cache first
            CacheEntry<V> entry = memoryCache.get(key);
            
            if (entry != null) {
                if (entry.isExpired()) {
                    // Upgrade to write lock for removal
                    lock.readLock().unlock();
                    lock.writeLock().lock();
                    try {
                        memoryCache.remove(key);
                        deleteDiskEntry(key);
                        statistics.recordMiss();
                        return null;
                    } finally {
                        lock.writeLock().unlock();
                        lock.readLock().lock();
                    }
                }
                statistics.recordHit();
                return entry.getValue();
            }
            
            // Try loading from disk
            lock.readLock().unlock();
            lock.writeLock().lock();
            try {
                // Double-check after acquiring write lock
                entry = memoryCache.get(key);
                if (entry != null && !entry.isExpired()) {
                    statistics.recordHit();
                    return entry.getValue();
                }
                
                entry = deserializeFromDisk(key);
                if (entry != null && !entry.isExpired()) {
                    // Evict if necessary
                    if (memoryCache.size() >= maxMemoryEntries) {
                        evictLeastRecentlyUsed();
                    }
                    memoryCache.put(key, entry);
                    statistics.recordHit();
                    statistics.recordDiskRead();
                    return entry.getValue();
                } else if (entry != null) {
                    // Expired on disk
                    deleteDiskEntry(key);
                }
                
                statistics.recordMiss();
                return null;
            } finally {
                lock.writeLock().unlock();
                lock.readLock().lock();
            }
        } finally {
            lock.readLock().unlock();
        }
    }
    
    public boolean containsKey(String key) {
        lock.readLock().lock();
        try {
            if (memoryCache.containsKey(key)) {
                CacheEntry<V> entry = memoryCache.get(key);
                return entry != null && !entry.isExpired();
            }
            return getDiskPath(key).toFile().exists();
        } finally {
            lock.readLock().unlock();
        }
    }
    
    public void remove(String key) {
        lock.writeLock().lock();
        try {
            memoryCache.remove(key);
            deleteDiskEntry(key);
        } finally {
            lock.writeLock().unlock();
        }
    }
    
    public void clear() {
        lock.writeLock().lock();
        try {
            memoryCache.clear();
            try {
                Files.walk(cacheDirectory)
                     .filter(p -> p.toString().endsWith(".cache"))
                     .forEach(p -> {
                         try { Files.deleteIfExists(p); } catch (IOException ignored) {}
                     });
            } catch (IOException e) {
                System.err.println("Error clearing disk cache: " + e.getMessage());
            }
        } finally {
            lock.writeLock().unlock();
        }
    }
    
    public int memorySize() {
        return memoryCache.size();
    }
    
    public long diskSize() {
        try {
            return Files.walk(cacheDirectory)
                        .filter(p -> p.toString().endsWith(".cache"))
                        .count();
        } catch (IOException e) {
            return -1;
        }
    }
    
    public CacheStatistics getStatistics() {
        return statistics;
    }
    
    public void shutdown() {
        cleanupExecutor.shutdown();
        try {
            cleanupExecutor.awaitTermination(5, TimeUnit.SECONDS);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
        
        // Persist all memory entries to disk
        lock.writeLock().lock();
        try {
            for (Map.Entry<String, CacheEntry<V>> entry : memoryCache.entrySet()) {
                if (!entry.getValue().isExpired()) {
                    serializeToDisk(entry.getKey(), entry.getValue());
                }
            }
        } finally {
            lock.writeLock().unlock();
        }
    }
    
    // Private helpers
    
    private Path getDiskPath(String key) {
        String safeKey = key.replaceAll("[^a-zA-Z0-9_\\-]", "_");
        // Use hash to avoid filename length issues
        String hash = Integer.toHexString(key.hashCode());
        return cacheDirectory.resolve(safeKey + "_" + hash + ".cache");
    }
    
    private void serializeToDisk(String key, CacheEntry<V> entry) {
        Path path = getDiskPath(key);
        try (ObjectOutputStream oos = new ObjectOutputStream(
                new BufferedOutputStream(new FileOutputStream(path.toFile())))) {
            oos.writeObject(entry);
            oos.flush();
            statistics.recordDiskWrite();
        } catch (IOException e) {
            System.err.println("Failed to serialize cache entry '" + key + "' to disk: " + e.getMessage());
        }
    }
    
    @SuppressWarnings("unchecked")
    private CacheEntry<V> deserializeFromDisk(String key) {
        Path path = getDiskPath(key);
        if (!Files.exists(path)) {
            return null;
        }
        try (ObjectInputStream ois = new ObjectInputStream(
                new BufferedInputStream(new FileInputStream(path.toFile())))) {
            return (CacheEntry<V>) ois.readObject();
        } catch (IOException | ClassNotFoundException e) {
            System.err.println("Failed to deserialize cache entry '" + key + "' from disk: " + e.getMessage());
            // Remove corrupted file
            try { Files.deleteIfExists(path); } catch (IOException ignored) {}
            return null;
        }
    }
    
    private void deleteDiskEntry(String key) {
        Path path = getDiskPath(key);
        try {
            Files.deleteIfExists(path);
        } catch (IOException e) {
            System.err.println("Failed to delete disk cache entry: " + e.getMessage());
        }
    }
    
    private void evictLeastRecentlyUsed() {
        if (memoryCache.isEmpty()) return;
        
        String lruKey = null;
        long oldestAccess = Long.MAX_VALUE;
        
        for (Map.Entry<String, CacheEntry<V>> entry : memoryCache.entrySet()) {
            if (entry.getValue().getLastAccessedAt() < oldestAccess) {
                oldestAccess = entry.getValue().getLastAccessedAt();
                lruKey = entry.getKey();
            }
        }
        
        if (lruKey != null) {
            CacheEntry<V> evicted = memoryCache.remove(lruKey);
            // Make sure evicted entry is still on disk
            if (evicted != null && !evicted.isExpired()) {
                serializeToDisk(lruKey, evicted);
            }
            statistics.recordEviction();
        }
    }
    
    private void cleanup() {
        lock.writeLock().lock();
        try {
            // Remove expired entries from memory
            Iterator<Map.Entry<String, CacheEntry<V>>> it = memoryCache.entrySet().iterator();
            while (it.hasNext()) {
                Map.Entry<String, CacheEntry<V>> entry = it.next();
                if (entry.getValue().isExpired()) {
                    it.remove();
                    deleteDiskEntry(entry.getKey());
                    statistics.recordEviction();
                }
            }
            
            // Clean expired disk entries
            try {
                Files.walk(cacheDirectory)
                     .filter(p -> p.toString().endsWith(".cache"))
                     .forEach(p -> {
                         try (ObjectInputStream ois = new ObjectInputStream(
                                 new BufferedInputStream(new FileInputStream(p.toFile())))) {
                             CacheEntry<?> entry = (CacheEntry<?>) ois.readObject();
                             if (entry.isExpired()) {
                                 Files.deleteIfExists(p);
                             }
                         } catch (Exception e) {
                             // Remove corrupted files
                             try { Files.deleteIfExists(p); } catch (IOException ignored) {}
                         }
                     });
            } catch (IOException e) {
                System.err.println("Error during disk cleanup: " + e.getMessage());
            }
        } finally {
            lock.writeLock().unlock();
        }
    }
    
    @SuppressWarnings("unchecked")
    private void loadIndexFromDisk() {
        try {
            Files.walk(cacheDirectory)
                 .filter(p -> p.toString().endsWith(".cache"))
                 .limit(maxMemoryEntries)
                 .forEach(p -> {
                     try (ObjectInputStream ois = new ObjectInputStream(
                             new BufferedInputStream(new FileInputStream(p.toFile())))) {
                         CacheEntry<V> entry = (CacheEntry<V>) ois.readObject();
                         if (!entry.isExpired()) {
                             memoryCache.put(entry.getKey(), entry);
                         } else {
                             Files.deleteIfExists(p);
                         }
                     } catch (Exception e) {
                         try { Files.deleteIfExists(p); } catch (IOException ignored) {}
                     }
                 });
            System.out.println("Loaded " + memoryCache.size() + " entries from disk cache.");
        } catch (IOException e) {
            System.err.println("Error loading cache index from disk: " + e.getMessage());
        }
    }
}

// Cache manager that provides typed caches
class CacheManager {
    
    private final DiskCache<Serializable> generalCache;
    private final DiskCache<UserPreferences> preferencesCache;
    private final DiskCache<SessionData> sessionCache;
    private final DiskCache<ComputationResult> computationCache;
    
    public CacheManager(String baseCacheDir, int maxMemoryEntries, long defaultTtlMillis) throws IOException {
        this.generalCache = new DiskCache<>(baseCacheDir + "/general", maxMemoryEntries, defaultTtlMillis);
        this.preferencesCache = new DiskCache<>(baseCacheDir + "/preferences", maxMemoryEntries, defaultTtlMillis);
        this.sessionCache = new DiskCache<>(baseCacheDir + "/sessions", maxMemoryEntries, 30 * 60 * 1000L); // 30 min default for sessions
        this.computationCache = new DiskCache<>(baseCacheDir + "/computations", maxMemoryEntries, defaultTtlMillis);
    }
    
    public DiskCache<Serializable> getGeneralCache() { return generalCache; }
    public DiskCache<UserPreferences> getPreferencesCache() { return preferencesCache; }
    public DiskCache<SessionData> getSessionCache() { return sessionCache; }
    public DiskCache<ComputationResult> getComputationCache() { return computationCache; }
    
    // Convenience method for caching expensive computations
    @SuppressWarnings("unchecked")
    public <T extends Serializable> T computeIfAbsent(String key, Callable<T> computation) throws Exception {
        Serializable cached = generalCache.get(key);
        if (cached != null) {
            return (T) cached;
        }
        
        long start = System.currentTimeMillis();
        T result = computation.call();
        long elapsed = System.currentTimeMillis() - start;
        
        generalCache.put(key, result);
        
        // Also store as computation result for tracking
        ComputationResult cr = new ComputationResult(key, result, elapsed);
        computationCache.put("comp_" + key, cr);
        
        return result;
    }
    
    public void printStatistics() {
        System.out.println("=== Cache Statistics ===");
        System.out.println("General:      " + generalCache.getStatistics() + " | Memory: " + generalCache.memorySize() + " | Disk: " + generalCache.diskSize());
        System.out.println("Preferences:  " + preferencesCache.getStatistics() + " | Memory: " + preferencesCache.memorySize() + " | Disk: " + preferencesCache.diskSize());
        System.out.println("Sessions:     " + sessionCache.getStatistics() + " | Memory: " + sessionCache.memorySize() + " | Disk: " + sessionCache.diskSize());
        System.out.println("Computations: " + computationCache.getStatistics() + " | Memory: " + computationCache.memorySize() + " | Disk: " + computationCache.diskSize());
    }
    
    public void shutdown() {
        generalCache.shutdown();
        preferencesCache.shutdown();
        sessionCache.shutdown();
        computationCache.shutdown();
    }
}

// Main demo class
public class DiskCacheSystem {
    
    public static void main(String[] args) {
        CacheManager cacheManager = null;
        
        try {
            // Initialize cache manager
            String cacheDir = System.getProperty("java.io.tmpdir") + "/disk_cache_demo";
            cacheManager = new CacheManager(cacheDir, 100, 5 * 60 * 1000L); // 5 min TTL
            
            System.out.println("Cache directory: " + cacheDir);
            System.out.println();
            
            // Demo 1: User Preferences
            System.out.println("=== User Preferences Demo ===");
            demoUserPreferences(cacheManager);
            
            // Demo 2: Session Data
            System.out.println("\n=== Session Data Demo ===");
            demoSessionData(cacheManager);
            
            // Demo 3: Expensive Computations
            System.out.println("\n=== Expensive Computation Caching Demo ===");
            demoExpensiveComputation(cacheManager);
            
            // Demo 4: Cache eviction (small memory limit)
            System.out.println("\n=== Cache Eviction Demo ===");
            demoEviction(cacheDir);
            
            // Demo 5: Concurrent access
            System.out.println("\n=== Concurrent Access Demo ===");
            demoConcurrentAccess(cacheManager);
            
            // Print final statistics
            System.out.println();
            cacheManager.printStatistics();
            
        } catch (Exception e) {
            System.err.println("Error: " + e.getMessage());
            e.printStackTrace();
        } finally {
            if (cacheManager != null) {
                cacheManager.shutdown();
                System.out.println("\nCache manager shut down gracefully.");
            }
        }
    }
    
    private static void demoUserPreferences(CacheManager cm) {
        DiskCache<UserPreferences> prefCache = cm.getPreferencesCache();
        
        // Create and cache user preferences
        UserPreferences prefs1 = new UserPreferences("user001", "dark", "en-US");
        prefs1.addSetting("fontSize", "14");
        prefs1.addSetting("notifications", "true");
        prefs1.addSetting("autoSave", "true");
        prefs1.addFavoriteCategory("Technology");
        prefs1.addFavoriteCategory("Science");
        
        prefCache.put("user_prefs_001", prefs1);
        System.out.println("Stored: " + prefs1);
        
        UserPreferences prefs2 = new UserPreferences("user002", "light", "fr-FR");
        prefs2.addSetting("fontSize", "16");
        prefs2.addSetting("notifications", "false");
        prefs2.addFavoriteCategory("Art");
        
        prefCache.put("user_prefs_002", prefs2);
        System.out.println("Stored: " + prefs2);
        
        // Retrieve from cache
        UserPreferences retrieved = prefCache.get("user_prefs_001");
        System.out.println("Retrieved: " + retrieved);
        
        // Verify data integrity
        assert retrieved != null;
        assert "dark".equals(retrieved.getTheme());
        assert retrieved.getSettings().size() == 3;
        System.out.println("Data integrity verified ✓");
    }
    
    private static void demoSessionData(CacheManager cm) {
        DiskCache<SessionData> sessionCache = cm.getSessionCache();
        
        // Create session
        SessionData session = new SessionData("sess_abc123", "user001", 60 * 60 * 1000L); // 1 hour
        session.setAttribute("cartItems", (Serializable) Arrays.asList("item1", "item2", "item3"));
        session.setAttribute("lastPage", "/dashboard");
        session.setAttribute("loginIp", "192.168.1.100");
        session.addAccessLog("2024-01-15T10:00:00 - Login");
        session.addAccessLog("2024-01-15T10:05:00 - Viewed dashboard");
        session.addAccessLog("2024-01-15T10:10:00 - Added item to cart");
        
        sessionCache.put("session_abc123", session);
        System.out.println("Stored session: " + session);
        
        // Retrieve session
        SessionData retrieved = sessionCache.get("session_abc123");
        System.out.println("Retrieved session: " + retrieved);
        System.out.println("Session active: " + retrieved.isActive());
        System.out.println("Cart items: " + retrieved.getAttribute("cartItems"));
        System.out.println("Access log entries: " + retrieved.getAccessLog().size());
    }
    
    @SuppressWarnings("unchecked")
    private static void demoExpensiveComputation(CacheManager cm) throws Exception {
        // First call - actually computes
        long start = System.currentTimeMillis();
        List<Integer> primes = cm.computeIfAbsent("primes_10000", () -> {
            System.out.println("  Computing primes (expensive operation)...");
            Thread.sleep(1000); // Simulate expensive computation
            return (Serializable) computePrimes(10000);
        });
        long firstCallTime = System.currentTimeMillis() - start;
        System.out.println("First call (computed): " + primes.size() + " primes found in " + firstCallTime + "ms");
        
        // Second call - from cache
        start = System.currentTimeMillis();
        List<Integer> cachedPrimes = cm.computeIfAbsent("primes_10000", () -> {
            System.out.println("  Computing primes (this should NOT appear)...");
            Thread.sleep(1000);
            return (Serializable) computePrimes(10000);
        });
        long secondCallTime = System.currentTimeMillis() - start;
        System.out.println("Second call (cached): " + cachedPrimes.size() + " primes found in " + secondCallTime + "ms");
        System.out.println("Speedup: " + (firstCallTime > 0 ? firstCallTime / Math.max(1, secondCallTime) : "∞") + "x");
        
        // Fibonacci computation
        Map<Integer, Long> fibonacci = cm.computeIfAbsent("fibonacci_50", () -> {
            System.out.println("  Computing Fibonacci sequence...");
            Thread.sleep(500);
            HashMap<Integer, Long> fib = new HashMap<>();
            long a = 0, b = 1;
            for (int i = 0; i < 50; i++) {
                fib.put(i, a);
                long temp = b;
                b = a + b;
                a = temp;
            }
            return fib;
        });
        System.out.println("Fibonacci(49) = " + fibonacci.get(49));
    }
    
    private static void demoEviction(String baseCacheDir) throws IOException {
        // Create a cache with very small memory limit
        DiskCache<Serializable> smallCache = new DiskCache<>(baseCacheDir + "/eviction_test", 3, 60000);
        
        // Add more entries than memory limit
        for (int i = 0; i < 6; i++) {
            smallCache.put("key_" + i, "value_" + i);
            System.out.println("Added key_" + i + " | Memory: " + smallCache.memorySize() + " | Disk: " + smallCache.diskSize());
        }
        
        // Verify all entries are still accessible (from disk if evicted from memory)
        System.out.println("\nRetrieving all entries:");
        for (int i = 0; i < 6; i++) {
            Serializable val = smallCache.get("key_" + i);
            System.out.println("  key_" + i + " = " + val + (val != null ? " ✓" : " ✗ (missing)"));
        }
        
        System.out.println("Eviction stats: " + smallCache.getStatistics());
        smallCache.shutdown();
    }
    
    private static void demoConcurrentAccess(CacheManager cm) throws InterruptedException {
        DiskCache<UserPreferences> prefCache = cm.getPreferencesCache();
        int numThreads = 10;
        int operationsPerThread = 50;
        CountDownLatch latch = new CountDownLatch(numThreads);
        ExecutorService executor = Executors.newFixedThreadPool(numThreads);
        
        long start = System.currentTimeMillis();
        
        for (int t = 0; t < numThreads; t++) {
            final int threadId = t;
            executor.submit(() -> {
                try {
                    for (int i = 0; i < operationsPerThread; i++) {
                        String key = "concurrent_user_" + (threadId * operationsPerThread + i);
                        UserPreferences prefs = new UserPreferences(
                                "user_" + threadId + "_" + i,
                                i % 2 == 0 ? "dark" : "light",
                                "en-US"
                        );
                        prefs.addSetting("threadId", String.valueOf(threadId));
                        prefCache.put(key, prefs);
                        
                        // Also read some entries
                        if (i > 0) {
                            String readKey = "concurrent_user_" + (threadId * operationsPerThread + i - 1);
                            prefCache.get(readKey);
                        }
                    }
                } finally {
                    latch.countDown();
                }
            });
        }
        
        latch.await();
        executor.shutdown();
        executor.awaitTermination(10, TimeUnit.SECONDS);
        
        long elapsed = System.currentTimeMillis() - start;
        int totalOps = numThreads * operationsPerThread * 2; // puts + gets
        System.out.println("Completed " + totalOps + " concurrent operations in " + elapsed + "ms");
        System.out.println("Throughput: " + (totalOps * 1000L / Math.max(1, elapsed)) + " ops/sec");
        System.out.println("Memory entries: " + prefCache.memorySize());
    }
    
    private static ArrayList<Integer> computePrimes(int limit) {
        ArrayList<Integer> primes = new ArrayList<>();
        boolean[] sieve = new boolean[limit + 1];
        Arrays.fill(sieve, true);
        sieve[0] = sieve[1] = false;
        
        for (int i = 2; i <= limit; i++) {
            if (sieve[i]) {
                primes.add(i);
                for (long j = (long) i * i; j <= limit; j += i) {
                    sieve[(int) j] = false;
                }
            }
        }
        return primes;
    }
}